#pragma once\\\\\n#include <cstdint>\\\\\n#include <cstddef>\\\\\n\\nvoid matmul(const float* A, const uint32_t* B, float* C, size_t M, size_t K) {\\\\n    for (size_t i = 0; i < M; ++i) {\\\\n        for (size_t j = 0; j < K; j += 16) {\\\\n            for (size_t t = 0; t < 16; ++t) {\\\\n                float sum = 0.0f;\\\\\n                for (size_t p = j; p < j + 16; ++p) {\\\\n                    size_t b_row = p / 32;\\\n                    size_t bit = (B[b_row * (K/32) + p/32] >> (p % 32)) & 1u;\\\n                    float sign = bit ? 1.0f : -1.0f;\\\n                    float a = A[i * K + p];\\\n                    sum += a * sign * (float)(bit == 1 ? 1.0f : -1.0f);\\\n                    // Actually, use bit as sign\\\n                }\\n                C[i * K + j + t] = sum;\\\n            }\\n        }\\n    }\\n}